local UIFriendFollow = class("UIFriendFollow", IGUILayout)

local cameraStatus = 2
UIFriendFollow.windowPosRecord = {}

local JoinGameLock = false

local function getFollower(followerId, times)
    times = times or 120
    if times <= 0 then
        return
    end
    local follower = PlayerManager:getPlayerByUserId(followerId)
    if follower and follower.userId ~= PlayerManager:getClientPlayer().userId then
        GUIFriendFollow:onIntoFollowMode(follower)
    else
        LuaTimer:schedule(function()
            getFollower(followerId, times - 1)
        end, 250)
    end
end

function UIFriendFollow:onLoad()
    self.btnQuit = self:getChildWindow("FriendsFollow-Quit", GUIType.Button)
    self.btnJoin = self:getChildWindow("FriendsFollow-Join", GUIType.Button)
    self.btnJoin:SetText(Lang:getString("gui.lang.joinGame"))
    self.btnChangeCamera = self:getChildWindow("FriendsFollow-Change-Camera", GUIType.Button)
    self.stCameraInfo1 = self:getChildWindow("FriendsFollow-Camera-Info-Text1", GUIType.StaticText)
    self.stCameraInfo1:SetText(Lang:getString("gui.lang.free.perspective"))
    self.stCameraInfo2 = self:getChildWindow("FriendsFollow-Camera-Info-Text2", GUIType.StaticText)
    self.stCameraInfo2:SetText(Lang:getString("gui.lang.follow.perspective"))
    self.stCameraInfo3 = self:getChildWindow("FriendsFollow-Camera-Info-Text3", GUIType.StaticText)
    self.siTipBg = self:getChildWindow("FriendsFollow-Tip-Bg", GUIType.StaticImage)
    self.stTipText = self:getChildWindow("FriendsFollow-Tip-Text", GUIType.StaticText)
    self.siCameraImage = self:getChildWindow("FriendsFollow-Camera-Image", GUIType.StaticImage)

    self.mainControl = GUIManager:getWindowByName("Main-Control")
    self.flyControl = GUIManager:getWindowByName("Main-FlyingControls")
    self.jumpControl = GUIManager:getWindowByName("Main-Jump-Controls")
    self.flyBtn = GUIManager:getWindowByName("Main-Fly")
    self.poleControl = GUIManager:getWindowByName("Main-PoleControl")
    self.poleControlMove = GUIManager:getWindowByName("Main-PoleControl-Move")

    self.isFreePerspective = false
    self:register()
end

function UIFriendFollow:onQuit()
    ClientHelper.putBoolPrefs("LockUIShowAndHide", false)
    CustomDialog.builder()
                .setContentText(Lang:getString("gui.message.exit.game"))
                .setLeftText("gui.cancel")
                .setRightText("gui.sure")
                .setLeftClickListener(function()
    end)
                .setRightClickListener(function()
        ClientHelper.dataReport("follow_quit_watch", "")
        Game:exitGame()
    end)        .show()
    ClientHelper.putBoolPrefs("LockUIShowAndHide", true)
end

function UIFriendFollow:register()
    self.btnQuit:registerEvent(GUIEvent.ButtonClick, function()
        self:onQuit()
    end)

    self.btnJoin:registerEvent(GUIEvent.ButtonClick, function()
        if not JoinGameLock then
            ClientHelper.dataReport("follow_game_enter", "")
            HostApi.followEnterGame(self.followerId, GameType)
            JoinGameLock = true
            LuaTimer:schedule(function()
                JoinGameLock = false
            end, 6000)
        end
    end)

    self.btnChangeCamera:registerEvent(GUIEvent.ButtonClick, function()
        ClientHelper.dataReport("follow_game_switch", "")
        cameraStatus = cameraStatus + 1
        if cameraStatus == 4 then
            cameraStatus = 2
        end
        self:onCameraChange(cameraStatus)
    end)

    self:registerDataCallBack("IntoFollowMode", function(followerId)
        getFollower(followerId)
    end)

    self:registerDataCallBack("JoinGameStatus", function(status)
        if status == "full" then
            self.siTipBg:SetVisible(true)
            self.btnJoin:SetEnabled(false)
            local text = Lang:getString("gui.lang.server.full.cannot.join.game")
            local width = math.max(self.stTipText:GetFont():GetTextExtent(text, 1) + 30, 450)
            self.siTipBg:SetWidth({ 0, width })
            self.stTipText:SetText(text)
        elseif status == "onlyWatch" or status == "gameStart" or status == "privateParty" then
            self.siTipBg:SetVisible(true)
            self.btnJoin:SetEnabled(false)
            local text = Lang:getString("gui.lang.cannot.join.game.in.this.mode")
            local width = math.max(self.stTipText:GetFont():GetTextExtent(text, 1) + 30, 450)
            self.siTipBg:SetWidth({ 0, width })
            self.stTipText:SetText(text)
        else
            self.siTipBg:SetVisible(false)
            self.btnJoin:SetEnabled(true)
        end
    end)

    Listener.registerCallBack(ShowSettingMenuEvent, function()
        if self.followerId == nil then
            return true
        end
        self:onQuit()
        return false
    end)

end

function UIFriendFollow:onIntoFollowMode(follower)
    ClientHelper.putBoolPrefs("RenderHeadText", false)
    GUIManager:hideAllLayout()
    GUIManager:hideAllSubLayout()
    ---隐藏main上面的子控件
    local mainLayout = GUIManager:getMainControl()
    local count = mainLayout:GetChildCount()
    if count == 0 then
        return
    end
    for index = 1, count do
        mainLayout:GetChildByIndex(index - 1):SetVisible(false)
    end
    ---隐藏ToolBar
    GUIManager:getToolBar():SetVisible(false)
    GUIManager:getWindowByName("MiniMap", GUIType.Layout):SetVisible(false)

    self.followerId = follower.userId
    GUIFriendFollow.follower = follower.Player
    GUIFriendFollow:show(follower:getName())
    ClientHelper.putBoolPrefs("LockUIShowAndHide", true)
end

function UIFriendFollow:onShow(name)
    self:onCameraChange(2)
    cameraStatus = 2
    self.stCameraInfo3:SetText(name)

    local statusControl = GUIManager:getWindowByName("Main-MoveState")
    if statusControl then
        statusControl:SetXPosition({ 99, 0 })
    end
    local watchTip = GUIManager:getWindowByName("Main-Watch-Battle-Tip")
    if watchTip then
        watchTip:SetXPosition({ 98, 0 })
    end
end

function UIFriendFollow:onCameraChange(cameraStatus)
    local imageName = "set:friends_follow.json image:perspective_" .. cameraStatus
    self.siCameraImage:SetImage(imageName)

    ---初始化时设置镜头不抖动和玩家actor不可见，设置第三人称视角

    if cameraStatus == 3 then
        ---解除摄像机与人物的锁定,设置为自由镜头
        self.isFreePerspective = true
        Blockman.Instance():setPersonView(0)
        self.stCameraInfo1:SetVisible(true)
        self.stCameraInfo2:SetVisible(false)
        self.stCameraInfo3:SetVisible(false)
    else
        self.isFreePerspective = false
        Blockman.Instance():setPersonView(1)
        self.stCameraInfo1:SetVisible(false)
        self.stCameraInfo2:SetVisible(true)
        self.stCameraInfo3:SetVisible(true)
    end
end

function UIFriendFollow:onTick(frameTime)
    self:checkMoveControlVisible()
    local player = PlayerManager:getPlayerByUserId(self.followerId)
    if not player then
        Blockman.Instance().renderViewEntity = PlayerManager:getClientPlayer().Player
        return
    end
    local follower = player.Player
    if not follower then
        Blockman.Instance().renderViewEntity = PlayerManager:getClientPlayer().Player
        return
    end
    PlayerManager:getClientPlayer().Player:setActorInvisible(true)
    if self.isFreePerspective == false then
        ---设置玩家坐标为跟随着坐
        local selfPlayer = PlayerManager:getClientPlayer().Player
        local position = VectorUtil.add3(follower.position, VectorUtil.newVector3(0, 1.62, 0))
        selfPlayer:setPosition(position)
        if not Blockman.Instance().m_gameSettings:isMouseMoving() then
            self:onPlayerMouseMoving(selfPlayer, follower, frameTime)
        end
        Blockman.Instance().renderViewEntity = follower
    else
        Blockman.Instance().renderViewEntity = PlayerManager:getClientPlayer().Player
    end
end

function UIFriendFollow:onPlayerMouseMoving(player, follower, frameTime)
    ---当玩家滑动屏幕时，摄像机不再随被跟随者转动，松手后摄像机转回被跟随者视角
    local yaw = follower:getYaw()
    local pitch = follower:getPitch()
    local yawDiff = math.fmod(yaw - player.rotationYaw, 360)
    if yawDiff > 180 or yawDiff < -180 then
        yawDiff = -yawDiff
    end
    local pitchDiff = pitch - player.rotationPitch
    local speed = 360
    ---设置yaw值
    if math.abs(yawDiff) < (frameTime / 1000) * speed then
        player.rotationYaw = yaw
    else
        player.rotationYaw = player.rotationYaw + (yawDiff / math.abs(yawDiff)) * speed * (frameTime / 1000)
    end
    ---设置pitch值
    if math.abs(pitch - player.rotationPitch) < (frameTime / 1000) * speed then
        player.rotationPitch = pitch
    else
        player.rotationPitch = player.rotationPitch + (pitchDiff / math.abs(pitchDiff)) * speed * (frameTime / 1000)
    end
end

function UIFriendFollow:checkMoveControlVisible()
    if self.isFreePerspective then
        if Blockman.Instance().m_gameSettings.usePole == 0 then
            self.mainControl:SetVisible(true)
            self.poleControl:SetVisible(false)
            self.poleControlMove:SetVisible(false)
        else
            self.mainControl:SetVisible(false)
            self.poleControl:SetVisible(true)
            self.poleControlMove:SetVisible(true)
        end
        if PlayerManager:getClientPlayer().Player:getIsFlying() then
            self.flyBtn:SetVisible(false)
            self.jumpControl:SetVisible(false)
            self.flyControl:SetVisible(true)
        else
            self.flyBtn:SetVisible(true)
            self.jumpControl:SetVisible(true)
            self.flyControl:SetVisible(false)
        end
    else
        self.mainControl:SetVisible(false)
        self.jumpControl:SetVisible(false)
        self.flyBtn:SetVisible(false)
        self.flyControl:SetVisible(false)
        self.poleControl:SetVisible(false)
        self.poleControlMove:SetVisible(false)
    end
end

return UIFriendFollow